using UnityEngine;public class SdvSkinRuntimeLoader : MonoBehaviour{    public enum ApplyMode    {        ExternalOnly,        CabinOnly,        Both    }    [Header("Mode")]    public ApplyMode applyMode = ApplyMode.Both;    public bool applyOnStart = true;    public bool verboseLog = true;    [Header("External Targets")]    public Renderer roadLaneRenderer;    public Renderer flowStripRenderer;    public SpriteRenderer vehicleSpriteRenderer;    public SpriteRenderer warningSpriteRenderer;    [Header("Cabin Targets")]    public SpriteRenderer clusterBackgroundSpriteRenderer;    public SpriteRenderer clusterNeedleSpriteRenderer;    public SpriteRenderer cabinCarSpriteRenderer;    public Renderer[] ambientZoneRenderers;    [Header("Resources Root")]    public string resourcesRoot = "Skins/unity_skin_pack_v1";    [ContextMenu("Apply Skin")]    public void ApplySkin()    {        if (applyMode == ApplyMode.ExternalOnly || applyMode == ApplyMode.Both)        {            ApplyExternal();        }        if (applyMode == ApplyMode.CabinOnly || applyMode == ApplyMode.Both)        {            ApplyCabin();        }    }    private void Start()    {        if (applyOnStart)        {            ApplySkin();        }    }    private void ApplyExternal()    {        Texture2D roadTex = LoadTexture("external/road/road_2lane_dark02");        Texture2D mapTex = LoadTexture("external/background/map_base");        Sprite markerSprite = LoadSprite("external/markers/car_marker");        Sprite warningSprite = LoadSprite("external/icons/warning_alert");        if (roadLaneRenderer != null && roadTex != null)        {            roadLaneRenderer.material.mainTexture = roadTex;        }        if (flowStripRenderer != null && mapTex != null)        {            flowStripRenderer.material.mainTexture = mapTex;        }        if (vehicleSpriteRenderer != null && markerSprite != null)        {            vehicleSpriteRenderer.sprite = markerSprite;        }        if (warningSpriteRenderer != null && warningSprite != null)        {            warningSpriteRenderer.sprite = warningSprite;        }        Log("Applied external skin.");    }    private void ApplyCabin()    {        Sprite clusterBg = LoadSprite("cabin/cluster/cluster_bg_xj");        Sprite clusterNeedle = LoadSprite("cabin/cluster/cluster_needle_mph");        Sprite cabinCar = LoadSprite("cabin/icons/car");        Texture2D ambientBase = LoadTexture("cabin/ambient/zone_background");        if (clusterBackgroundSpriteRenderer != null && clusterBg != null)        {            clusterBackgroundSpriteRenderer.sprite = clusterBg;        }        if (clusterNeedleSpriteRenderer != null && clusterNeedle != null)        {            clusterNeedleSpriteRenderer.sprite = clusterNeedle;        }        if (cabinCarSpriteRenderer != null && cabinCar != null)        {            cabinCarSpriteRenderer.sprite = cabinCar;        }        if (ambientZoneRenderers != null && ambientBase != null)        {            foreach (Renderer r in ambientZoneRenderers)            {                if (r != null)                {                    r.material.mainTexture = ambientBase;                }            }        }        Log("Applied cabin skin.");    }    private Texture2D LoadTexture(string relativePath)    {        return Resources.Load<Texture2D>(resourcesRoot + "/" + relativePath);    }    private Sprite LoadSprite(string relativePath)    {        return Resources.Load<Sprite>(resourcesRoot + "/" + relativePath);    }    private void Log(string message)    {        if (verboseLog)        {            Debug.Log("[SdvSkinRuntimeLoader] " + message);        }    }}